import classNames from "classnames";
import { MouseEvent, useEffect, useState } from "react";
import Button from "./button";
import { IButtonToggle } from "./type";

export default function Toggle(props: IButtonToggle) {
	const {
		ref,
		active,
		activeClass,
		after,
		disabled,
		children,
		className,
		toggable,
		onClick,
		onToggle,
		...restProps
	} = props;

	const [isActive, setIsActive] = useState(active);
	const [done, setDone] = useState(true);

	const toggle = async () => {
		const hasAfter = !!after;
		const nextActive = !isActive;

		const canToggle = toggable ? await toggable() : true;
		if (!canToggle) return;

		setIsActive(nextActive);
		setDone(!hasAfter);
		onToggle?.(nextActive);

		if (!hasAfter) return;

		setTimeout(() => {
			setDone(true);
		}, 16);
	};

	const handleClick = (e: MouseEvent<HTMLElement>) => {
		onClick?.(e);

		!disabled && toggle();
	};

	useEffect(() => {
		setIsActive(active);
		setDone(true);
	}, [active]);

	return (
		<Button
			ref={ref}
			className={classNames(
				className,
				{ [activeClass || ""]: isActive },
				"i-btn-toggle",
			)}
			{...restProps}
			onClick={handleClick}
		>
			<div
				className={classNames("i-btn-toggle-content", {
					"i-btn-toggle-active": done,
				})}
			>
				{isActive ? (after ?? children) : children}
			</div>
		</Button>
	);
}
